
theta1 = deg2rad(0); %[control:slider:090c]{"position":[18,19]}
theta2 = deg2rad(0); %[control:slider:0e33]{"position":[18,19]}
theta3 = deg2rad(0); %[control:slider:062c]{"position":[18,19]}
theta4 = deg2rad(0); %[control:slider:97cf]{"position":[18,19]}

a1 = dh_link_to_transformation_matrix(0, pi/2, 0, theta1);
a2 = dh_link_to_transformation_matrix(0.15, 0, 0, theta2+3*pi/4);
a3 = dh_link_to_transformation_matrix(0.15, 0, 0, theta3-pi/4);
a4 = dh_link_to_transformation_matrix(0, pi/2, 0, theta4); % d4 might be something
T = a1 * a2 * a3 * a4 % shows end effector position %[output:3e5af83c]
T02 = a1 * a2 %[output:719f9923]
T03 = a1 * a2 * a3; % should overlap with end effector

%[text] 3D Plot
plot3(0,0,0, "bo", MarkerFaceColor="b") %[output:019c2058]
hold on %[output:019c2058]
plot3(T02(1,4), T02(2,4), T02(3,4), "go", MarkerFaceColor="g") %[output:019c2058]
plot3(T03(1,4), T03(2,4), T03(3,4), "yo", MarkerFaceColor="y") %[output:019c2058]
plot3(T(1,4), T(2,4), T(3,4), "ro", MarkerFaceColor="r") %[output:019c2058]
legend("Origin", "J2", "J3", "End effector") %[output:019c2058]
grid on %[output:019c2058]
grid minor %[output:019c2058]
hold off %[output:019c2058]
xlim([-0.5 0.5]) %[output:019c2058]
ylim([-0.5 0.5]) %[output:019c2058]
zlim([-0.5 0.5]) %[output:019c2058]
xlabel("X") %[output:019c2058]
ylabel("Y") %[output:019c2058]
zlabel("Z") %[output:019c2058]
%[text] 

